using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; } = 3;
}

public class TicketResponse
{
    public required string Category { get; set; }
    public float Confidence { get; set; }
    public Dictionary<string, float> Scores { get; set; } = new();
}

/// <summary>
/// Holds the category label names in the order matching the Score array indices.
/// </summary>
public class CategoryLabels(string[] values)
{
    public string[] Values { get; } = values;
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class ModelTrainerService
{
    /// <summary>
    /// Trains a multiclass classification model, logs cross-validation metrics,
    /// saves the model to disk, and returns the ordered category label names.
    /// </summary>
    public static string[] TrainAndEvaluate(string dataPath, string modelPath)
    {
        Console.WriteLine("═══════════════════════════════════════════════════");
        Console.WriteLine("  Ticket Classification – Model Training");
        Console.WriteLine("═══════════════════════════════════════════════════");
        Console.WriteLine($"  Data source : {dataPath}");
        Console.WriteLine();

        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate(
                "Features",
                "SubjectFeaturized",
                "DescriptionFeaturized",
                nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        // Cross-validate for evaluation metrics (appropriate for small datasets)
        var cvResults = mlContext.MulticlassClassification
            .CrossValidate(data, pipeline, numberOfFolds: 3);

        Console.WriteLine("  Cross-Validation Results (3 folds):");
        Console.WriteLine("  ───────────────────────────────────────────────");

        for (int i = 0; i < cvResults.Count; i++)
        {
            var m = cvResults[i].Metrics;
            Console.WriteLine(
                $"  Fold {i + 1}:  MicroAccuracy={m.MicroAccuracy:F4}" +
                $"  MacroAccuracy={m.MacroAccuracy:F4}" +
                $"  LogLoss={m.LogLoss:F4}");
        }

        Console.WriteLine("  ───────────────────────────────────────────────");
        Console.WriteLine(
            $"  Avg  :  MicroAccuracy={cvResults.Average(r => r.Metrics.MicroAccuracy):F4}" +
            $"  MacroAccuracy={cvResults.Average(r => r.Metrics.MacroAccuracy):F4}" +
            $"  LogLoss={cvResults.Average(r => r.Metrics.LogLoss):F4}");
        Console.WriteLine();

        // Train final model on all available data
        var model = pipeline.Fit(data);

        // Extract ordered label names from the Score column slot metadata
        var transformedData = model.Transform(data);
        var scoreColumn = transformedData.Schema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        var labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        mlContext.Model.Save(model, data.Schema, modelPath);

        Console.WriteLine($"  Categories : [{string.Join(", ", labels)}]");
        Console.WriteLine($"  Model saved: {modelPath}");
        Console.WriteLine("═══════════════════════════════════════════════════");
        Console.WriteLine();

        return labels;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketsController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
    CategoryLabels categoryLabels) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionPool.Predict(input);

        var scores = new Dictionary<string, float>();
        var labels = categoryLabels.Values;
        for (int i = 0; i < labels.Length && i < prediction.Score.Length; i++)
            scores[labels[i]] = prediction.Score[i];

        return Ok(new TicketResponse
        {
            Category = prediction.PredictedCategory,
            Confidence = prediction.Score.Max(),
            Scores = scores
        });
    }
}

